      console.error(`[Shader] ${typeName} compile error:\n${info}\n\nSource:\n${annotated}`)
      gl.deleteShader(shader)
      throw new Error(`${typeName} shader compile failed: ${info}`)
    }
    return shader
  }

  private link(vert: WebGLShader, frag: WebGLShader, name: string): WebGLProgram {
    const { gl } = this
    const program = gl.createProgram()!
    gl.attachShader(program, vert)
    gl.attachShader(program, frag)
    gl.linkProgram(program)
    gl.deleteShader(vert)
    gl.deleteShader(frag)
    if (!gl.getProgramParameter(program, gl.LINK_STATUS)) {
      const info = gl.getProgramInfoLog(program) ?? 'Unknown error'
      console.error(`[Shader] Program "${name}" link error: ${info}`)
      throw new Error(`Shader program link failed: ${info}`)
    }
    return program
  }

  private collectUniforms(program: WebGLProgram, source: string): Map<string, WebGLUniformLocation | null> {
    const { gl } = this
    const uniforms = new Map<string, WebGLUniformLocation | null>()
    // Extract uniform names from source via regex
    const regex = /uniform\s+\S+\s+(\w+)/g
    let match: RegExpExecArray | null
    while ((match = regex.exec(source)) !== null) {
      const name = match[1]
      if (!uniforms.has(name)) {
        uniforms.set(name, gl.getUniformLocation(program, name))
      }
    }
    return uniforms
  }

  setUniform(prog: CompiledProgram, name: string, ...args: number[]): void {
    const loc = prog.uniforms.get(name)
    if (loc === undefined || loc === null) return
    const { gl } = this
    switch (args.length) {
      case 1: gl.uniform1f(loc, args[0]); break
      case 2: gl.uniform2f(loc, args[0], args[1]); break
      case 3: gl.uniform3f(loc, args[0], args[1], args[2]); break
      case 4: gl.uniform4f(loc, args[0], args[1], args[2], args[3]); break
    }
  }

  setUniformi(prog: CompiledProgram, name: string, ...args: number[]): void {
    const loc = prog.uniforms.get(name)
    if (loc === undefined || loc === null) return
    const { gl } = this
    switch (args.length) {
      case 1: gl.uniform1i(loc, args[0]); break
      case 2: gl.uniform2i(loc, args[0], args[1]); break
      case 3: gl.uniform3i(loc, args[0], args[1], args[2]); break
    }
  }

  setUniformMat3(prog: CompiledProgram, name: string, matrix: Float32Array): void {
    const loc = prog.uniforms.get(name)
    if (loc === undefined || loc === null) return
    this.gl.uniformMatrix3fv(loc, false, matrix)
  }

  setUniformMat4(prog: CompiledProgram, name: string, matrix: Float32Array): void {
    const loc = prog.uniforms.get(name)
    if (loc === undefined || loc === null) return
    this.gl.uniformMatrix4fv(loc, false, matrix)
  }

  setUniformBool(prog: CompiledProgram, name: string, value: boolean): void {
    const loc = prog.uniforms.get(name)
    if (loc === undefined || loc === null) return
    this.gl.uniform1i(loc, value ? 1 : 0)
  }

  invalidateCache() {
    for (const prog of this.cache.values()) {
      this.gl.deleteProgram(prog.program)
    }
    this.cache.clear()
  }
}

export interface FileDialogFilter {
  name: string
  extensions: string[]
}

export interface SaveFileOptions {
  suggestedName: string
  filters?: FileDialogFilter[]
  mime?: string
}

export interface OpenTextFileOptions {
  filters?: FileDialogFilter[]
}

export interface OpenTextFileResult {
  name: string
  text: string
}

export function isTauriRuntime(): boolean {
  return typeof window !== 'undefined' && (
    '__TAURI_INTERNALS__' in window ||
    '__TAURI__' in window
  )
}

export async function saveBytes(data: Uint8Array, options: SaveFileOptions): Promise<boolean> {
  if (isTauriRuntime()) {
    const { save } = await import('@tauri-apps/plugin-dialog')
    const { writeFile } = await import('@tauri-apps/plugin-fs')
    const target = await save({
      defaultPath: options.suggestedName,
      filters: options.filters,
    })

    if (!target || Array.isArray(target)) return false
    await writeFile(target, data)
    return true
  }

  const blob = new Blob([toArrayBuffer(data)], { type: options.mime ?? 'application/octet-stream' })
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url
  a.download = options.suggestedName
  a.click()
  URL.revokeObjectURL(url)
  return true
}

export async function saveText(text: string, options: SaveFileOptions): Promise<boolean> {
  if (isTauriRuntime()) {
    const { save } = await import('@tauri-apps/plugin-dialog')
    const { writeTextFile } = await import('@tauri-apps/plugin-fs')
    const target = await save({
      defaultPath: options.suggestedName,
      filters: options.filters,
    })

    if (!target || Array.isArray(target)) return false
    await writeTextFile(target, text)
    return true
  }

  const blob = new Blob([text], { type: options.mime ?? 'text/plain;charset=utf-8' })
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url
  a.download = options.suggestedName
  a.click()
  URL.revokeObjectURL(url)
  return true
}

export async function openTextFile(options: OpenTextFileOptions = {}): Promise<OpenTextFileResult | null> {
  if (isTauriRuntime()) {
    const { open } = await import('@tauri-apps/plugin-dialog')
    const { readTextFile } = await import('@tauri-apps/plugin-fs')
    const target = await open({
      multiple: false,
      directory: false,
      filters: options.filters,
    })

    if (!target || Array.isArray(target)) return null
    const text = await readTextFile(target)
    const parts = target.replace(/\\/g, '/').split('/')
    return {
      name: parts[parts.length - 1] || 'file.txt',
      text,
    }
  }

  return new Promise((resolve, reject) => {
    const input = document.createElement('input')
    input.type = 'file'
    input.accept = toAcceptString(options.filters)
    input.id = 'platform-open-text-file'
    input.name = 'platform-open-text-file'

    input.addEventListener('change', async () => {
      const file = input.files?.[0]
      if (!file) {
        resolve(null)
        return
      }

      try {
        resolve({
          name: file.name,
          text: await file.text(),
        })
      } catch (error) {
        reject(error)
      }
    })

    input.click()
  })
}

function toAcceptString(filters?: FileDialogFilter[]): string {
  if (!filters || filters.length === 0) return ''
  return filters.flatMap(filter => filter.extensions.map(ext => `.${ext}`)).join(',')
}

function toArrayBuffer(data: Uint8Array): ArrayBuffer {
  return data.buffer.slice(data.byteOffset, data.byteOffset + data.byteLength) as ArrayBuffer
}

#version 300 es
precision highp float;

in vec2 vUv;
out vec4 fragColor;

// --- Per-layer uniforms ---
uniform vec3 u_scale;
uniform float u_amplitude;
uniform vec3 u_offset;
uniform mat3 u_rotation;
uniform float u_seed;
uniform float u_sliceZ;    // current Z slice [0..1]
uniform vec2 u_remapInput;
uniform vec2 u_remapOutput;
uniform float u_edgeFeather;
uniform float u_animPhase;
uniform float u_animEvolutions;
uniform bool u_invert;

// Noise type: worley mode (injected below via noiseEval)
// Distortion (injected below via applyDistortion or identity)

const float ANIM_RADIUS = 4.0;

vec3 animatedDomainOffset() {
  float angle = u_animPhase * u_animEvolutions * 6.28318530718;
  vec3 axisA = normalize(vec3(
    hash11(u_seed * 0.031 + 21.0) * 2.0 - 1.0,
    hash11(u_seed * 0.037 + 22.0) * 2.0 - 1.0,
    hash11(u_seed * 0.041 + 23.0) * 2.0 - 1.0
  ));
  vec3 axisB = normalize(vec3(
    hash11(u_seed * 0.043 + 24.0) * 2.0 - 1.0,
    hash11(u_seed * 0.047 + 25.0) * 2.0 - 1.0,
    hash11(u_seed * 0.053 + 26.0) * 2.0 - 1.0
  ));
  return (axisA * cos(angle) + axisB * sin(angle)) * ANIM_RADIUS;
}

float sampleNoiseAtVolumePos(vec3 volumePos) {
  vec3 p = volumePos;

  // Apply scale, offset, rotation
  p = p * u_scale + u_offset;
  p = u_rotation * p;
  p += animatedDomainOffset();

  // Apply distortion (function injected by shader assembler)
  p = applyDistortion(p);

  // Evaluate noise (function injected by shader assembler)
  return noiseEval(p);
}

float sampleNoiseTileable(vec3 volumePos) {
  float tileSize = max(u_tileSize, 0.0001);
  vec3 blend = clamp(volumePos / tileSize, 0.0, 1.0);

  float n000 = sampleNoiseAtVolumePos(volumePos);
  float n100 = sampleNoiseAtVolumePos(volumePos - vec3(tileSize, 0.0, 0.0));
  float n010 = sampleNoiseAtVolumePos(volumePos - vec3(0.0, tileSize, 0.0));
  float n110 = sampleNoiseAtVolumePos(volumePos - vec3(tileSize, tileSize, 0.0));
  float n001 = sampleNoiseAtVolumePos(volumePos - vec3(0.0, 0.0, tileSize));
  float n101 = sampleNoiseAtVolumePos(volumePos - vec3(tileSize, 0.0, tileSize));
  float n011 = sampleNoiseAtVolumePos(volumePos - vec3(0.0, tileSize, tileSize));
  float n111 = sampleNoiseAtVolumePos(volumePos - vec3(tileSize, tileSize, tileSize));

  float nx00 = mix(n000, n100, blend.x);
  float nx10 = mix(n010, n110, blend.x);
  float nx01 = mix(n001, n101, blend.x);
  float nx11 = mix(n011, n111, blend.x);

  float nxy0 = mix(nx00, nx10, blend.y);
  float nxy1 = mix(nx01, nx11, blend.y);

  return mix(nxy0, nxy1, blend.z);
}

void main() {
  vec3 volumePos = vec3(vUv, u_sliceZ);
  float n = u_tileable
    ? sampleNoiseTileable(volumePos)
    : sampleNoiseAtVolumePos(volumePos);

  if (u_edgeFeather > 0.0 && !u_tileable) {
    float edgeDist = min(min(min(volumePos.x, 1.0 - volumePos.x), min(volumePos.y, 1.0 - volumePos.y)), min(volumePos.z, 1.0 - volumePos.z));
    float feather = smoothstep(0.0, max(u_edgeFeather, 0.0001), edgeDist);
    n *= feather;
  }

  // Remap
  n = remap(n, u_remapInput.x, u_remapInput.y, u_remapOutput.x, u_remapOutput.y);

  // Amplitude
  n *= u_amplitude;

  // Invert
  if (u_invert) n = 1.0 - n;

  n = clamp(n, 0.0, 1.0);
  fragColor = vec4(n, n, n, 1.0);
}

#version 300 es
precision highp float;

in vec2 vUv;
out vec4 fragColor;

// --- Per-layer uniforms ---
uniform vec3 u_scale;
uniform float u_amplitude;
uniform vec3 u_offset;
uniform mat3 u_rotation;
uniform float u_seed;
uniform float u_sliceZ;    // current Z slice [0..1]
uniform vec2 u_remapInput;
uniform vec2 u_remapOutput;
uniform vec4 u_remapCurve;
uniform vec3 u_featherWidth;
uniform int u_featherShape;
uniform vec4 u_featherCurve;
uniform float u_animPhase;
uniform float u_animEvolutions;
uniform bool u_invert;

// Noise type: worley mode (injected below via noiseEval)
// Distortion (injected below via applyDistortion or identity)

const float ANIM_RADIUS = 4.0;

vec3 animatedDomainOffset() {
  float angle = u_animPhase * u_animEvolutions * 6.28318530718;
  vec3 axisA = normalize(vec3(
    hash11(u_seed * 0.031 + 21.0) * 2.0 - 1.0,
    hash11(u_seed * 0.037 + 22.0) * 2.0 - 1.0,
    hash11(u_seed * 0.041 + 23.0) * 2.0 - 1.0
  ));
  vec3 axisB = normalize(vec3(
    hash11(u_seed * 0.043 + 24.0) * 2.0 - 1.0,
    hash11(u_seed * 0.047 + 25.0) * 2.0 - 1.0,
    hash11(u_seed * 0.053 + 26.0) * 2.0 - 1.0
  ));
  return (axisA * cos(angle) + axisB * sin(angle)) * ANIM_RADIUS;
}

float sampleNoiseAtVolumePos(vec3 volumePos) {
  vec3 p = volumePos;

  // Apply scale, offset, rotation
  p = p * u_scale + u_offset;
  p = u_rotation * p;
  p += animatedDomainOffset();

  // Apply distortion (function injected by shader assembler)
  p = applyDistortion(p);

  // Evaluate noise (function injected by shader assembler)
  return noiseEval(p);
}

float sampleNoiseTileable(vec3 volumePos) {
  const float tileSize = 1.0;
  vec3 blend = clamp(volumePos / tileSize, 0.0, 1.0);

  float n000 = sampleNoiseAtVolumePos(volumePos);
  float n100 = sampleNoiseAtVolumePos(volumePos - vec3(tileSize, 0.0, 0.0));
  float n010 = sampleNoiseAtVolumePos(volumePos - vec3(0.0, tileSize, 0.0));
  float n110 = sampleNoiseAtVolumePos(volumePos - vec3(tileSize, tileSize, 0.0));
  float n001 = sampleNoiseAtVolumePos(volumePos - vec3(0.0, 0.0, tileSize));
  float n101 = sampleNoiseAtVolumePos(volumePos - vec3(tileSize, 0.0, tileSize));
  float n011 = sampleNoiseAtVolumePos(volumePos - vec3(0.0, tileSize, tileSize));
  float n111 = sampleNoiseAtVolumePos(volumePos - vec3(tileSize, tileSize, tileSize));

  float nx00 = mix(n000, n100, blend.x);
  float nx10 = mix(n010, n110, blend.x);
  float nx01 = mix(n001, n101, blend.x);
  float nx11 = mix(n011, n111, blend.x);

  float nxy0 = mix(nx00, nx10, blend.y);
  float nxy1 = mix(nx01, nx11, blend.y);

  return mix(nxy0, nxy1, blend.z);
}

float saturate01(float v) {
  return clamp(v, 0.0, 1.0);
}

vec2 cubicBezierPoint(vec2 p1, vec2 p2, float t) {
  float omt = 1.0 - t;
  return 3.0 * omt * omt * t * p1
    + 3.0 * omt * t * t * p2
    + t * t * t * vec2(1.0);
}

float evaluateBezierCurve(vec4 curve, float x) {
  vec2 p1 = curve.xy;
  vec2 p2 = curve.zw;
  float lo = 0.0;
  float hi = 1.0;
  for (int i = 0; i < 10; i++) {
    float mid = 0.5 * (lo + hi);
    float bx = cubicBezierPoint(p1, p2, mid).x;
    if (bx < x) lo = mid;
    else hi = mid;
  }
  return cubicBezierPoint(p1, p2, 0.5 * (lo + hi)).y;
}

float applyRemapCurve(float v) {
  float t = saturate01((v - u_remapInput.x) / max(u_remapInput.y - u_remapInput.x, 0.0001));
  t = evaluateBezierCurve(u_remapCurve, t);
  return mix(u_remapOutput.x, u_remapOutput.y, t);
}

float featherMaskBox(vec3 volumePos) {
  vec3 widths = max(u_featherWidth, vec3(0.0));
  if (widths.x <= 0.0001 && widths.y <= 0.0001 && widths.z <= 0.0001) return 1.0;

  vec3 edgeDist = min(volumePos, 1.0 - volumePos);
  vec3 axisMask = vec3(1.0);

  if (widths.x > 0.0001) axisMask.x = saturate01(edgeDist.x / widths.x);
  if (widths.y > 0.0001) axisMask.y = saturate01(edgeDist.y / widths.y);
  if (widths.z > 0.0001) axisMask.z = saturate01(edgeDist.z / widths.z);

  return min(axisMask.x, min(axisMask.y, axisMask.z));
}

float ellipsoidRadiusAlongDir(vec3 dir, vec3 radii) {
  return 1.0 / max(length(dir / max(radii, vec3(0.0001))), 0.0001);
}

float featherMaskSphere(vec3 volumePos) {
  vec3 widths = clamp(u_featherWidth, vec3(0.0), vec3(0.499));
  if (widths.x <= 0.0001 && widths.y <= 0.0001 && widths.z <= 0.0001) return 1.0;

  vec3 centered = volumePos - 0.5;
  float dist = length(centered);
  if (dist <= 0.0001) return 1.0;

  vec3 dir = centered / dist;
  vec3 outerRadii = vec3(0.5);
  vec3 innerRadii = max(outerRadii - widths, vec3(0.0005));
  float outerDist = ellipsoidRadiusAlongDir(dir, outerRadii);
  float innerDist = min(outerDist, ellipsoidRadiusAlongDir(dir, innerRadii));

  return 1.0 - saturate01((dist - innerDist) / max(outerDist - innerDist, 0.0001));
}

float applyFeather(vec3 volumePos, float density) {
  float mask = u_featherShape == 1
    ? featherMaskSphere(volumePos)
    : featherMaskBox(volumePos);

  mask = evaluateBezierCurve(u_featherCurve, saturate01(mask));
  return density * mask;
}

void main() {
  vec3 volumePos = vec3(vUv, u_sliceZ);
  float n = sampleNoiseTileable(volumePos);

  // Remap
  n = applyRemapCurve(n);

  // Amplitude
  n *= u_amplitude;

  // Invert
  if (u_invert) n = 1.0 - n;

  // Spatial feather / shaping
  n = applyFeather(volumePos, n);

  n = clamp(n, 0.0, 1.0);
  fragColor = vec4(n, n, n, 1.0);
}

