  border-radius: var(--radius-sm);
  font-size: 12px;
  color: var(--text-secondary);
  transition: all var(--t-fast);
  white-space: nowrap;
}

.top-btn:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
  border-color: var(--border-focus);
}

.top-btn.active {
  background: var(--bg-active);
  color: var(--accent);
  border-color: var(--accent);
}

.top-btn.accent {
  background: var(--accent);
  color: white;
  border-color: transparent;
  font-weight: 600;
}

.top-btn.accent:hover {
  background: var(--accent-hover);
  color: white;
}

.top-field {
  display: flex;
  align-items: center;
  gap: var(--sp-1);
}

.top-label {
  font-size: 11px;
  color: var(--text-muted);
  white-space: nowrap;
}

.top-input {
  width: 56px;
  padding: 4px var(--sp-2);
  font-size: 12px;
  background: var(--bg-control);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
}

/* ─── Segmented Controls ─── */

.seg-group {
  display: flex;
  background: var(--bg-control);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  overflow: hidden;
}

.seg-btn {
  padding: 4px 10px;
  font-size: 12px;
  color: var(--text-secondary);
  border-right: 1px solid var(--border);
  transition: all var(--t-fast);
  white-space: nowrap;
}

.seg-btn:last-child { border-right: none; }

.seg-btn:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.seg-btn.active {
  background: var(--accent);
  color: white;
}

.seg-btn.sm {
  padding: 3px 7px;
  font-size: 11px;
}

/* ─── Progress bar ─── */

.progress-bar {
  width: 120px;
  height: 4px;
  background: var(--bg-control);
  border-radius: 2px;
  overflow: hidden;
}

.progress-fill {
  height: 100%;
  background: var(--accent);
  border-radius: 2px;
  transition: width 100ms linear;
  box-shadow: 0 0 6px var(--accent-glow);
}

/* ─── Panels ─── */

.layer-panel {
  background: var(--bg-panel);
  display: flex;
  flex-direction: column;
  overflow: hidden;
  flex: 0 0 36%;
